const request = require('supertest');
const jwt = require('jsonwebtoken');
const app = require('./server');
const db = require('./db');

jest.mock('./db');

describe('JWT Authentication Refactor', () => {
  const JWT_SECRET = process.env.JWT_SECRET || 'your-secret-key-change-in-production';

  describe('POST /auth/login', () => {
    it('returns JWT token on valid credentials', async () => {
      db.query.mockResolvedValue({
        rows: [{ id: 1, password_hash: 'hashed_password' }]
      });

      const response = await request(app)
        .post('/auth/login')
        .send({ email: 'user@example.com', password: 'password123' });

      expect(response.status).toBe(200);
      expect(response.body.token).toBeDefined();
    });

    it('returns 401 on invalid credentials', async () => {
      db.query.mockResolvedValue({ rows: [] });

      const response = await request(app)
        .post('/auth/login')
        .send({ email: 'user@example.com', password: 'wrongpassword' });

      expect(response.status).toBe(401);
    });
  });

  describe('Protected Routes with JWT', () => {
    let validToken;

    beforeEach(() => {
      validToken = jwt.sign({ userId: 1 }, JWT_SECRET, { expiresIn: '1h' });
    });

    it('allows access with valid token', async () => {
      db.query.mockResolvedValue({
        rows: [{ id: 1, email: 'user@example.com', name: 'John Doe' }]
      });

      const response = await request(app)
        .get('/api/profile')
        .set('Authorization', `Bearer ${validToken}`);

      expect(response.status).toBe(200);
    });

    it('denies access without token', async () => {
      const response = await request(app).get('/api/profile');
      expect(response.status).toBe(401);
    });

    it('denies access with invalid token', async () => {
      const response = await request(app)
        .get('/api/profile')
        .set('Authorization', 'Bearer invalid_token');
      expect(response.status).toBe(401);
    });
  });
});
